const normalizedData = $('Normalize Input').item.json;
const reviewResult = $('Parse Review Result').item.json;

const messageContent = `@aiadpulse12/agent4-campaign ✅ CONTENT APPROVED\n\n📦 Product: ${normalizedData.product_name}\n⭐ Final Score: ${reviewResult.overall_score}/10\n📝 Summary: ${reviewResult.approval_summary}\n\n➡️ ACTION: Build the final campaign brief for this product.`;

return [{
  json: {
    product_name: normalizedData.product_name,
    product_description: normalizedData.product_description,
    target_audience: normalizedData.target_audience,
    chat_id: normalizedData.chat_id,
    research_data: normalizedData.research_data,
    content_data: normalizedData.content_data,
    overall_score: reviewResult.overall_score,
    approval_summary: reviewResult.approval_summary,
    band_message: messageContent,
    band_api_key: 'band_a_1780711851_ivz0SZp_4XJCN2Pxm6vAcojmzslFWulq'
  }
}];

const normalizedData = $('Normalize Input').item.json;
const reviewResult = $('Parse Review Result').item.json;

// issues_found can be string or array — handle both
let issuesText = '';
if (Array.isArray(reviewResult.issues_found)) {
  issuesText = reviewResult.issues_found.join('\n');
} else if (typeof reviewResult.issues_found === 'string') {
  issuesText = reviewResult.issues_found;
} else {
  issuesText = 'See revision notes below';
}

const messageContent = `@aiadpulse12/agent2-content ❌ REVISION REQUIRED (Attempt ${normalizedData.attempt || 1}/3)\n\n📦 Product: ${normalizedData.product_name}\n⭐ Score: ${reviewResult.overall_score}/10\n\n⚠️ Issues Found:\n${issuesText}\n\n📝 Revision Notes:\n${reviewResult.revision_notes}\n\n➡️ ACTION: Fix ALL issues above and resubmit.`;

return [{
  json: {
    product_name: normalizedData.product_name,
    product_description: normalizedData.product_description,
    target_audience: normalizedData.target_audience,
    chat_id: normalizedData.chat_id,
    research_data: normalizedData.research_data,
    revision_notes: reviewResult.revision_notes,
    attempt: (normalizedData.attempt || 1) + 1,
    band_message: messageContent,
    band_api_key: 'band_a_1780711851_ivz0SZp_4XJCN2Pxm6vAcojmzslFWulq'
  }
}];

